import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

function Dashboard() {
  const [members, setMembers] = useState([]);
  const [tasks, setTasks] = useState([]);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [taskName, setTaskName] = useState('');
  const [taskDescription, setTaskDescription] = useState('');
  const [assignTo, setAssignTo] = useState('');
  const [assignToAll, setAssignToAll] = useState(false);
  const [error, setError] = useState('');
  const { logout, user } = useAuth();

  useEffect(() => {
    fetchMembers();
    fetchTasks();
  }, []);

  const fetchMembers = async () => {
    try {
      const response = await axios.get('/members');
      setMembers(response.data);
    } catch (err) {
      setError('Failed to fetch members.');
    }
  };

  const fetchTasks = async () => {
    try {
      // Mock tasks for now - you can add a real endpoint later
      setTasks([
        { id: 1, name: 'bike fault electrical complaint', status: 'Pending' }
      ]);
    } catch (err) {
      setError('Failed to fetch tasks.');
    }
  };

  const handleAddMember = async (e) => {
    e.preventDefault();
    setError('');
    try {
      await axios.post('/members', { name, email, role: 'Member' });
      setName('');
      setEmail('');
      fetchMembers();
    } catch (err) {
      setError('Failed to add member. Email might already exist.');
    }
  };

  const handleDeleteMember = async (memberId) => {
    try {
      await axios.delete(`/members/${memberId}`);
      fetchMembers();
    } catch (err) {
      setError('Failed to delete member.');
    }
  };

  const handleCreateTask = async (e) => {
    e.preventDefault();
    setError('');
    try {
      const newTask = {
        id: tasks.length + 1,
        name: taskName,
        description: taskDescription,
        status: 'Pending'
      };
      setTasks([...tasks, newTask]);
      setTaskName('');
      setTaskDescription('');
      setAssignTo('');
      setAssignToAll(false);
    } catch (err) {
      setError('Failed to create task.');
    }
  };

  return (
    <div className="App">
      <div className="sidebar">
        <div className="sidebar-icon active">🏠</div>
        <div className="sidebar-icon">👥</div>
        <div className="sidebar-icon">📋</div>
        <div className="sidebar-icon">⚙️</div>
      </div>

      <div className="main-content">
        <div className="header">
          <div className="header-left">
            <div className="header-logo">TaskFlow</div>
            <a className="header-link">Back to Groups</a>
            <div className="header-title">Team Collaboration Hub</div>
          </div>
          <button onClick={logout} className="btn btn-logout">Logout</button>
        </div>

        <div className="content-area">
          <div className="content-column">
            <div className="member-form">
              <h3>Team Members</h3>
              {error && <p className="error">{error}</p>}

              <div style={{display: 'flex', flexDirection: 'column', gap: '10px'}}>
                {members.map(member => (
                  <div key={member.id} style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '12px', background: 'var(--light)', borderRadius: '10px'}}>
                    <span>{member.name} - {member.email}</span>
                    <button 
                      onClick={() => handleDeleteMember(member.id)} 
                      className="btn btn-danger"
                      style={{padding: '6px 12px', fontSize: '12px'}}
                    >
                      Delete
                    </button>
                  </div>
                ))}
              </div>

              <form onSubmit={handleAddMember} style={{marginTop: '20px', paddingTop: '20px', borderTop: '1px solid var(--border)'}}>
                <input
                  type="text"
                  placeholder="Name"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  required
                  style={{marginBottom: '10px'}}
                />
                <input
                  type="email"
                  placeholder="Email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  style={{marginBottom: '10px'}}
                />
                <button type="submit" className="btn btn-primary">Add Member</button>
              </form>
            </div>
          </div>

          <div className="content-column">
            <div className="member-form">
              <h3>Tasks</h3>

              <form onSubmit={handleCreateTask}>
                <input
                  type="text"
                  placeholder="Task name"
                  value={taskName}
                  onChange={(e) => setTaskName(e.target.value)}
                  required
                  style={{marginBottom: '10px'}}
                />
                <input
                  type="text"
                  placeholder="Description"
                  value={taskDescription}
                  onChange={(e) => setTaskDescription(e.target.value)}
                  style={{marginBottom: '10px'}}
                />
                <div style={{display: 'flex', gap: '10px'}}>
                  <button type="submit" className="btn btn-primary">Create Task</button>
                  <button type="button" className="btn" style={{background: 'var(--gray)', color: 'white'}}>Cancel</button>
                </div>
              </form>

              {tasks.length > 0 && (
                <div style={{marginTop: '20px', borderTop: '1px solid var(--border)', paddingTop: '20px'}}>
                  <h4 style={{marginBottom: '15px'}}>Existing Tasks</h4>
                  {tasks.map(task => (
                    <div key={task.id} style={{padding: '15px', background: 'var(--light)', borderRadius: '10px', marginBottom: '10px'}}>
                      <div style={{fontWeight: '600', marginBottom: '5px'}}>{task.name}</div>
                      <div style={{fontSize: '0.9rem', color: 'var(--gray)'}}>{task.description}</div>
                      <div style={{fontSize: '0.8rem', color: 'var(--secondary)', marginTop: '5px'}}>{task.status}</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
